/**
 * Generate docs/helm/index.mdx from k8s/helm/README.md and k8s/helm/values.yaml.
 *
 * Intro prose comes from README.md (generated by helm-docs); the Values section
 * embeds the raw values.yaml as a syntax-highlighted code block.
 *
 * Runs as part of `npm run prepare` before every Fern build. Do not edit
 * docs/helm/index.mdx by hand — it is gitignored and regenerated each build.
 */

import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const scriptDir = dirname(fileURLToPath(import.meta.url));
const fernDir = resolve(scriptDir, "..");
const repoRoot = resolve(fernDir, "..", "..");

const README = resolve(repoRoot, "k8s", "helm", "README.md");
const VALUES = resolve(repoRoot, "k8s", "helm", "values.yaml");
const OUTPUT = resolve(repoRoot, "docs", "helm", "index.mdx");

const FRONTMATTER = `---
title: "NeMo Platform Helm Chart"
description: ""
---
`;

const DROP_LINE =
  /^Documentation can be found at: https:\/\/docs\.nvidia\.com\/nemo-platform\.\s*$/;

const DEPLOYMENT_LINK =
  /For deployment instructions, see https:\/\/docs\.nvidia\.com\/nemo-platform\/documentation\/self-managed-deployment\/setup\./;

const DEPLOYMENT_LINK_REPLACEMENT =
  "For deployment guide, see " +
  "[Self-Managed Deployment](/documentation/self-managed-deployment/setup) " +
  "in the NeMo Platform documentation.";

function extractIntro(readme) {
  const lines = readme.split("\n");
  const out = [];
  let skipH1 = true;

  for (const line of lines) {
    if (line.trim() === "## Values") break;

    if (skipH1 && line.startsWith("# ")) {
      skipH1 = false;
      continue;
    }

    if (DROP_LINE.test(line)) continue;

    out.push(line.replace(DEPLOYMENT_LINK, DEPLOYMENT_LINK_REPLACEMENT));
  }

  while (out.length && !out[out.length - 1].trim()) out.pop();
  return out.join("\n");
}

function buildMdx(intro, valuesYaml) {
  return (
    FRONTMATTER +
    "\n" +
    intro +
    "\n\n" +
    "## Values\n\n" +
    "The following is the complete `values.yaml` for the NeMo Platform Helm Chart.\n" +
    "All configuration options are documented inline with comments.\n\n" +
    "```yaml wordWrap\n" +
    valuesYaml.trimEnd() +
    "\n```\n"
  );
}

export function syncHelmDocs() {
  const mdxText = buildMdx(
    extractIntro(readFileSync(README, "utf8")),
    readFileSync(VALUES, "utf8"),
  );

  let current = "";
  try {
    current = readFileSync(OUTPUT, "utf8");
  } catch {
    // file doesn't exist yet — will be created below
  }
  if (current === mdxText) return;

  mkdirSync(dirname(OUTPUT), { recursive: true });
  writeFileSync(OUTPUT, mdxText);
  console.log(`[sync-helm-docs] Updated ${OUTPUT.replace(repoRoot + "/", "")}`);
}

// Support running directly: node scripts/sync-helm-docs.mjs
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  syncHelmDocs();
}
